API_name: nchu_course_search_by_assessment_method
Description:
{
  "description": "依評量方式搜尋課程。常見評量方式：期中考, 期末考, 作業, 報告, 實作, 出席, 小考, 作品 等。回傳包含使用指定評量方式之課程的 JSON 字串",
  "required_parameters": [
    {
      "name": "method",
      "type": "STRING",
      "description": "欲搜尋的評量方式（例如：實作、報告、期末考）"
    }
  ],
  "optional_parameters": [
    {
      "name": "limit",
      "type": "NUMBER",
      "description": "最多回傳幾筆結果（預設為 20）",
      "default": 20
    },
    {
      "name": "semester",
      "type": "STRING",
      "description": "學年期代碼。若未指定，則使用最新學期。",
      "default": null
    }
  ]
}

